query getCreatedUsers($skip: Int, $take: Int, $where: UserModelFilterInput, $order: [UserModelSortInput!]) {
  usersPaged(skip: $skip, take: $take, where: $where, order: $order) {
    totalCount
    items {
      id
      userName
      fullName
      email
      telegramUserName
      roles {
        name
        id
        __typename
      }
      company {
        id
        nameEn
        nameRu
        __typename
      }
      client {
        id
        nic
        __typename
      }
      isEnabled
      __typename
    }
    __typename
  }
}

