graphql.query:
query getInvoicesForPackingPaged($skip: Int, $take: Int, $where: InvoiceFilterInput, $order: [InvoiceSortInput!]) {
  invoicesForPackingPaged(skip: $skip, take: $take, where: $where, order: $order) {
    items {
      id
      number
      date
      packingInfo {
        skuItemsCount
        __typename
      }
      packingCount
      packingInfo {
        assignedTo {
          fullName
          __typename
        }
        __typename
      }
      packingInfo {
        status {
          id
          nameRu
          __typename
        }
        __typename
      }
      sum
      sender {
        company {
          name
          id
          __typename
        }
        __typename
      }
      currency {
        isoCode
        __typename
      }
      client {
        nic
        id
        __typename
      }
      documents {
        fileName
        id
        fileStoragePath
        __typename
      }
      grossWeight
      netWeight
      itemCount
      orders {
        number
        id
        status
        __typename
      }
      wayBills {
        name
        uid
        id
        __typename
      }
      createdDate
      __typename
    }
    totalCount
    __typename
  }
}
